const request = items[0]?.json || {};
const input = request.body || request;
const payload = input.payload || {};
const description = String(payload.description || '').trim();
const descriptionLower = description.toLowerCase();
const priority = String(payload.priority || '0');
const photoCount = Number(payload.photo_count || 0);
let aiDisposition = 'sellable';
let aiConfidence = 0.62;
let aiRecommendedAction = 'Sichtpruefung durch Qualitaetsteam.';
if (priority === '3' || /(totalschaden|zerstoert|eingedrueckt|bruch|gebrochen)/.test(descriptionLower)) {
  aiDisposition = 'scrap';
  aiConfidence = 0.94;
  aiRecommendedAction = 'Ware sperren, aussondern und Schichtleitung informieren.';
} else if (priority === '2' || photoCount > 0 || /(defekt|gerissen|feucht|nass|offen|beschaedigt)/.test(descriptionLower)) {
  aiDisposition = 'quarantine';
  aiConfidence = 0.87;
  aiRecommendedAction = 'Ware sperren und manuelle Pruefung anfordern.';
} else if (/(kratzer|etikett|verpackung|kleber|nacharbeit)/.test(descriptionLower)) {
  aiDisposition = 'rework';
  aiConfidence = 0.79;
  aiRecommendedAction = 'Nacharbeit pruefen und Verpackung korrigieren.';
}
const severityLabel = priority === '3' ? 'kritisch' : priority === '2' ? 'hoch' : 'normal';
const aiSummary = description
  ? `Automatische V1-Bewertung (${severityLabel}): ${description}`
  : `Automatische V1-Bewertung fuer Alert ${payload.alert_id || ''}.`;
const notify = priority === '2' || priority === '3' || photoCount > 0 || aiDisposition !== 'sellable';
return [{ json: {
  correlation_id: input.correlation_id,
  alert_id: payload.alert_id,
  ai_disposition: aiDisposition,
  ai_confidence: aiConfidence,
  ai_summary: aiSummary,
  ai_recommended_action: aiRecommendedAction,
  ai_provider: 'n8n-heuristic-agent',
  ai_model: 'quality-v1',
  log_message: `Alert ${payload.name || payload.alert_id}: ${aiDisposition} | Prioritaet ${priority} | ${description || 'ohne Beschreibung'}`,
  email_subject: `[QA] Alert ${payload.name || payload.alert_id} (${severityLabel})`,
  email_html: `<p><strong>Alert:</strong> ${payload.name || payload.alert_id}</p><p><strong>Einstufung:</strong> ${aiDisposition}</p><p><strong>Empfehlung:</strong> ${aiRecommendedAction}</p><p><strong>Beschreibung:</strong> ${description || 'ohne Beschreibung'}</p><p><strong>Fotos:</strong> ${photoCount}</p>`,
  notify,
} }];

const request = items[0]?.json || {};
const input = request.body || request;
const payload = input.payload || {};
const kitName = String(payload.kit_name || '').trim();
const lineName = String(payload.line_display_name || 'dem aktuellen Artikel').trim();
const question = String(payload.text || '').trim();
const intent = String(payload.intent || 'unknown');
const stockSummary = String(payload.stock_summary_text || '').trim();
const obsidianContext = String(payload.obsidian_context_text || '').trim();
const voiceIntro = String(payload.voice_intro || '').trim();
const currentLocation = String(payload.current_location_label || '').trim();
const recommendation = payload.default_recommendation || null;
const defaultRecommendationText = String(payload.default_recommendation_text || '').trim();
const pickingContext = input.picking_context || {};
let ttsText = '';
if (intent === 'stock_query' && stockSummary) {
  ttsText = stockSummary;
} else if (intent === 'problem' && recommendation) {
  const sourceName = (typeof recommendation === 'object' && recommendation.recommended_location) ? recommendation.recommended_location : 'einem Alternativplatz';
  ttsText = `Am aktuellen Platz ${currentLocation || 'des Artikels'} ist kein verfuegbarer Bestand mehr vorhanden. Ich habe einen Nachschub aus ${sourceName} vorbereitet.`;
} else if (obsidianContext) {
  ttsText = `Du baust ${kitName || 'gerade einen Auftrag'}. ${obsidianContext}`;
} else if (voiceIntro) {
  ttsText = voiceIntro;
} else if (kitName) {
  ttsText = `Du baust ${kitName}. Aktuell geht es um ${lineName}.`;
} else {
  ttsText = `Aktuell geht es um ${lineName}. Frage: ${question || 'keine Frage uebermittelt'}.`;
}
const altLocationIds = Array.isArray(pickingContext.alternative_location_ids) ? pickingContext.alternative_location_ids : [];
return [{ json: {
  status: 'ok',
  tts_text: ttsText,
  action: 'none',
  referenced_product_id: null,
  referenced_location_id: null,
  confidence: 0.8,
  source: 'n8n-context-agent',
  correlation_id: input.correlation_id,
  recommendation,
  default_recommendation_text: defaultRecommendationText,
  picking_context: pickingContext,
  alt_location_ids: altLocationIds,
} }];

const input = items[0]?.json || {};
const VALID_ACTIONS = ['none', 'ask_supervisor', 'check_alt_location', 'suggest_replenishment'];
const pickingContext = input.picking_context || {};
const altLocationIds = input.alt_location_ids || [];
let ttsText = input.tts_text;
let action = input.action;
let referencedProductId = input.referenced_product_id;
let referencedLocationId = input.referenced_location_id;
let confidence = input.confidence;
const fallbackTts = input.default_recommendation_text || ttsText || 'Bitte wende dich an den Schichtleiter.';
let validationFailed = false;
if (!ttsText || typeof ttsText !== 'string' || ttsText.trim() === '') {
  validationFailed = true;
}
if (!VALID_ACTIONS.includes(action)) {
  validationFailed = true;
}
if (referencedProductId !== null && referencedProductId !== pickingContext.product_id) {
  validationFailed = true;
}
if (referencedLocationId !== null) {
  const isMainLocation = referencedLocationId === pickingContext.location_id;
  const isAltLocation = altLocationIds.includes(referencedLocationId);
  if (!isMainLocation && !isAltLocation) {
    validationFailed = true;
  }
}
if (typeof confidence !== 'number' || confidence < 0.5) {
  validationFailed = true;
}
if (validationFailed) {
  ttsText = fallbackTts;
  action = 'none';
  referencedProductId = null;
  referencedLocationId = null;
  confidence = 0.5;
}
return [{ json: {
  status: input.status || 'ok',
  tts_text: ttsText,
  action,
  referenced_product_id: referencedProductId,
  referenced_location_id: referencedLocationId,
  confidence,
  source: input.source,
  correlation_id: input.correlation_id,
  recommendation: input.recommendation || null,
} }];

const input = items[0]?.json || {};
const exec = input.execution || {};
const wf = input.workflow || {};
const err = exec.error || {};
const workflow_name = String(wf.name || 'unknown-workflow');
const workflow_key = workflow_name.toLowerCase();
const failing_node = String(err.node || 'unknown');
const error_message = String(err.message || 'Unknown error');
const execution_url = String(exec.url || '');

const normalizeNumericId = (value) => {
  if (value === undefined || value === null || value === '') {
    return null;
  }
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : null;
};

const collectItemJsons = () => {
  const collected = [];
  try {
    const data = exec.data || {};
    const resultData = data.resultData || {};
    const runData = resultData.runData || {};
    for (const nodeRuns of Object.values(runData)) {
      if (!Array.isArray(nodeRuns)) {
        continue;
      }
      for (const run of nodeRuns) {
        const branches = run && run.data && run.data.main;
        if (!Array.isArray(branches)) {
          continue;
        }
        for (const branch of branches) {
          if (!Array.isArray(branch)) {
            continue;
          }
          for (const item of branch) {
            if (item && item.json && typeof item.json === 'object') {
              collected.push(item.json);
            }
          }
        }
      }
    }
  } catch (e) {
    return collected;
  }
  return collected;
};

let correlation_id = '';
let alert_id = null;
let picking_id = null;

for (const itemJson of collectItemJsons()) {
  if (!correlation_id && itemJson.correlation_id) {
    correlation_id = String(itemJson.correlation_id);
  }
  const payload = itemJson.payload || {};
  const pickingContext = itemJson.picking_context || {};

  if (alert_id === null) {
    alert_id = normalizeNumericId(itemJson.alert_id ?? payload.alert_id);
  }
  if (picking_id === null) {
    picking_id = normalizeNumericId(itemJson.picking_id ?? pickingContext.picking_id ?? payload.picking_id);
  }

  if (correlation_id && alert_id !== null && picking_id !== null) {
    break;
  }
}

let route = 'log_only';
if (workflow_key.includes('quality') && alert_id !== null) {
  route = 'quality';
} else if (workflow_key.includes('shortage') && picking_id !== null) {
  route = 'shortage';
}

return [{ json: {
  workflow_name,
  failing_node,
  error_message,
  correlation_id,
  execution_url,
  alert_id,
  picking_id,
  route,
} }];

const request = items[0]?.json || {};
const input = request.body || request;
const payload = input.payload || {};
const recommendation = payload.recommendation || null;
const pickingContext = input.picking_context || {};
const picker = input.picker || {};
if (!recommendation || !recommendation.recommended_location_id || !pickingContext.location_id) {
  return [];
}
const ticketText = [
  'Automatisch erzeugter Nachschubauftrag aus dem Voice-Exception-Pfad.',
  payload.text ? `Meldung: ${payload.text}` : '',
  recommendation.reason ? `Grund: ${recommendation.reason}` : '',
].filter(Boolean).join(' ');
return [{ json: {
  correlation_id: input.correlation_id,
  picking_id: pickingContext.picking_id,
  product_id: pickingContext.product_id,
  location_id: pickingContext.location_id,
  recommended_location_id: recommendation.recommended_location_id,
  recommended_location: recommendation.recommended_location || '',
  quantity: recommendation.quantity || 1,
  reason: recommendation.reason || 'Automatische Nachschubanforderung nach Fehlmengen-Hinweis.',
  ticket_text: ticketText,
  requested_by_user_id: payload.requested_by_user_id || picker.user_id || null,
  requested_by_name: picker.name || '',
  log_message: `Nachschub fuer Picking ${pickingContext.picking_id} von ${recommendation.recommended_location || 'Alternativplatz'} nach Zielplatz ${pickingContext.location_id} angestossen.`,
} }];
